class Solution:
    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        if indexDiff <= 0 or valueDiff < 0:
            return False
        width = valueDiff + 1
        buckets = {}
        for i, v in enumerate(nums):
            b = v // width
            if b in buckets:
                return True
            if b - 1 in buckets and abs(v - buckets[b - 1]) <= valueDiff:
                return True
            if b + 1 in buckets and abs(v - buckets[b + 1]) <= valueDiff:
                return True
            buckets[b] = v
            if i >= indexDiff:
                del buckets[nums[i - indexDiff] // width]
        return False

