var containsNearbyAlmostDuplicate = function(nums, indexDiff, valueDiff) {
    if (indexDiff <= 0 || valueDiff < 0) return false;
    const width = valueDiff + 1;
    const buckets = new Map();
    const bucketOf = (v) => Math.floor(v / width);
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        const b = bucketOf(v);
        if (buckets.has(b)) return true;
        if (buckets.has(b - 1) && Math.abs(v - buckets.get(b - 1)) <= valueDiff) return true;
        if (buckets.has(b + 1) && Math.abs(v - buckets.get(b + 1)) <= valueDiff) return true;
        buckets.set(b, v);
        if (i >= indexDiff) buckets.delete(bucketOf(nums[i - indexDiff]));
    }
    return false;
};
